<Stats id="monster-decapus--stats" atts={[16,13,15,10,11,12]} bab={4} cmb={7} cmbP="+11 grapple" cmd={18} cmdP="can't be tripped" feats={[["Skill Focus"," (Bluff)"],"Toughness",["Weapon Focus"," (tentacles)"]]} skills={{"acro":{"b":7,"x":"-1 jump"},"bluff":{"b":7},"climb":{"b":16},"ea":{"b":5},"intm":{"b":7},"per":{"b":11},"spc":{"b":6},"stl":{"b":9}}} racial="+4 Perception" lang={["Ak"]} sq="sound mimicry (voices), tentacles" />
