<Defense id="monster-deeplit--defense" ac={[19,12,17]} mod="+4 armor, +2 Dex, +3 natural" hp={[52,"7d8+21"]} fort="+5" ref="+4" will="+8" immune={<>blindness, <Link to="/umr/undead_traits">undead traits</Link></>} weak={["pattern susceptibility"]} />
