<Stats id="monster-div_akvan--stats" atts={[35,26,30,19,24,27]} bab={24} cmb={40} cmd={58} feats={["Awesome Blow","Cleave","Combat Reflexes","Critical Focus","Great Cleave","Improved Bull Rush","Improved Initiative",["Improved Critical"," (bite)"],"Multiattack","Power Attack","Staggering Critical","Stunning Critical"]} skills={{"acro":{"b":28,"x":"+36 when jumping"},"bluff":{"b":43},"diplo":{"b":31},"sm":{"b":30},"spc":{"b":19},"umd":{"b":23}}} racial="+8 Acrobatics when jumping, +8 Bluff" lang={["A","Ce","C","D","I",";",[<><Link to="/umr/telepathy">telepathy</Link> 100 ft.</>]]} sq="armor training 4" />
